import React, { useEffect, useState } from 'react';

import { api } from '../api/api';
import { Icon } from '../components/Icon';
import { PageHero } from '../components/UI';

interface Product {
    id: number;
    name: string;
    description: string;
    image_url: string;
    category: string;
    price: number;
}

const CatalogPage: React.FC = () => {
    const [products, setProducts] = useState<Product[]>([]);
    const [loading, setLoading] = useState<boolean>(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        api.getProducts()
            .then(data => {
                setProducts(data);
                setLoading(false);
            })
            .catch(err => {
                console.error(err);
                setError('Не удалось загрузить каталог');
                setLoading(false);
            });
    }, []);

    if (loading) {
        return (
            <div className="page-shell text-center">
                <div className="mx-auto grid h-16 w-16 place-items-center rounded-2xl bg-white shadow-card">
                    <Icon name="settings" className="h-7 w-7 animate-spin text-factory-600" />
                </div>
                <p className="mt-4 font-semibold text-graphite-500">Загрузка каталога...</p>
            </div>
        );
    }

    if (error) return <div className="page-shell text-center font-semibold text-red-600">{error}</div>;

    return (
        <div>
            <PageHero
                label="Каталог"
                title="Каталог продукции"
                description="Карточки изделий получили современную визуальную систему: чистые изображения, категории, цены и мягкие промышленные акценты."
            />

            <section className="page-shell pt-0">
                <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3">
                    {products.map(product => (
                        <article key={product.id} className="card-hover overflow-hidden p-4">
                            <div className="relative grid h-64 place-items-center overflow-hidden rounded-[1.35rem] bg-gradient-to-br from-white via-graphite-50 to-factory-50/50 p-4">
                                <div className="absolute inset-0 bg-grid-light technical-grid opacity-40" />
                                {product.image_url ? (
                                    <img
                                        src={product.image_url}
                                        alt={product.name}
                                        className="relative h-full w-full object-contain transition duration-500 hover:scale-105"
                                    />
                                ) : (
                                    <div className="relative grid h-24 w-24 place-items-center rounded-3xl bg-graphite-950 text-factory-200 shadow-card">
                                        <Icon name="factory" className="h-10 w-10" />
                                    </div>
                                )}
                                {product.category ? (
                                    <span className="absolute left-5 top-5 rounded-full bg-white/90 px-3 py-1 text-xs font-black text-factory-700 shadow-card">
                    {product.category}
                  </span>
                                ) : null}
                            </div>

                            <div className="p-2 pt-5">
                                <h3 className="font-display text-2xl font-black leading-tight text-graphite-950 text-balance">{product.name}</h3>
                                <p className="mt-3 line-clamp-3 text-sm leading-6 text-graphite-600">{product.description}</p>

                                <div className="mt-5 flex items-center justify-between gap-4 border-t border-graphite-100 pt-4">
                                    <span className="text-2xl font-black text-factory-700">{product.price} ₽</span>
                                    <span className="rounded-full bg-graphite-100 px-3 py-1 text-xs font-black text-graphite-600">
                    {product.category || 'Изделие'}
                  </span>
                                </div>
                            </div>
                        </article>
                    ))}
                </div>
            </section>
        </div>
    );
};

export default CatalogPage;
